<script lang="ts">
  const html: string = "<h1>Place</h1>\n\n<p>A place component displays information about a place, such as its name, address, description, and map or image. It is used in location directories, venue listings, and geographic references.</p>\n\n<p>This headless component uses an <code>&lt;article&gt;</code> element for self-contained place content semantics.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses <code>&lt;article&gt;</code> element for self-contained place semantics</li>\n<li><code>aria-label</code> describes the place for screen readers</li>\n<li>Contains slots for name, address, description, and image or map</li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>label</code>: string (optional) -- accessible label for the place</li>\n<li><code>children</code>: slot (required) -- place content</li>\n<li><code>...restProps</code>: Any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;Place label=\"Riverside Clinic, 42 Thames Road, London\"&gt;\n  &lt;h3&gt;Riverside Clinic&lt;/h3&gt;\n  &lt;address&gt;42 Thames Road, London SE1 7PB&lt;/address&gt;\n  &lt;p&gt;Walk-in clinic open Monday to Friday, 08:00 to 18:00.&lt;/p&gt;\n  &lt;TelLink href=\"tel:+442079876543\"&gt;020 7987 6543&lt;/TelLink&gt;\n  &lt;Image src=\"/maps/riverside-clinic.png\" label=\"Map showing Riverside Clinic location\" /&gt;\n&lt;/Place&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;Place label=\"Conference Room B, Level 3\"&gt;\n  &lt;h3&gt;Conference Room B&lt;/h3&gt;\n  &lt;p&gt;Level 3, East Wing&lt;/p&gt;\n  &lt;p&gt;Capacity: 20 people. Equipped with video conferencing.&lt;/p&gt;\n&lt;/Place&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>None -- place components are informational, not interactive</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>Implicit <code>article</code> role from <code>&lt;article&gt;</code> element</li>\n<li><code>aria-label</code> -- describes the place for screen readers</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use to display place information such as a clinic address, hospital location, or service area.</li>\n<li>Use when structured place data (name, address, description) needs semantic grouping.</li>\n<li>Use for venue listings, location directories, or geographic references.</li>\n<li>Use in combination with Image for maps or photos, and TelLink for contact numbers.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for organisations -- use Organization instead.</li>\n<li>Do not use for events at a location -- use Event instead.</li>\n<li>Do not use for simple inline addresses -- use a plain <code>&lt;address&gt;</code> element instead.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>This component provides an <code>&lt;article&gt;</code> element with optional <code>aria-label</code>, with zero visual styling. The consumer is responsible for all CSS including layout, map placement, and typography.</p>\n\n<h2>Styles</h2>\n\n<p>The consumer provides all CSS styling. The component renders with a <code>.place</code> class for targeting. No default styles are included -- this is a fully headless component.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders an <code>&lt;article&gt;</code> element with class <code>place</code></li>\n<li>Verify <code>aria-label</code> is applied when provided</li>\n<li>Verify child content is rendered correctly</li>\n<li>Verify pass-through attributes are applied</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Include location name, address, and a visual element (map or photo) for clear identification.</li>\n<li><strong>Developers</strong>: Use the <code>label</code> prop to identify the place for screen readers. Use semantic <code>&lt;address&gt;</code> elements for postal addresses.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>person</code> — a person component that contains other person-related information</li>\n<li><code>organization</code> — an organization component that contains other organization-related information</li>\n<li><code>address-input</code> — an input for searching or manually entering an address</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li><a href=\"https://developer.mozilla.org/en-US/docs/Web/HTML/Element/article\">MDN article element</a></li>\n</ul>";
</script>

